+        expected_rows: 50,
+        json_columns: &[],
+    },
+    TableSpec {
+        name: "agent_sessions",
+        order_by: "session_id",
+        expected_rows: 1_000,
+        json_columns: &[5, 6],
+    },
+    TableSpec {
+        name: "system_metrics",
+        order_by: "machine_id, collected_at",
+        expected_rows: 1_000,
+        json_columns: &[5, 6],
+    },
+];
